                else:
                    combined_alert[1].add(rule_id)

        if combined_alert is not None and len(combined_alert[1]) > 0:
            combined_alerts.append((combined_alert[0], list(combined_alert[1])))

    return flagged_trans, combined_alerts

def process_combined_alerts(alerts):
    for transaction_id, rules in alerts:
